3527   Use &U = I->getOperandUse(OpNo);
3528   Value *V = U.get();
3529   Type *VTy = V->getType();
3530 
3531   if (DemandedMask == fcNone) {
3532     if (isa<PoisonValue>(V))
3533       return false;
3534     replaceUse(U, PoisonValue::get(VTy));
3535     return true;
3536   }
3537 
3538   // Handle constant
3539   Instruction *VInst = dyn_cast<Instruction>(V);
3540   if (!VInst) {
3541     // Handle constants and arguments
3542     Known = computeKnownFPClass(V, fcAllFlags, I, Depth);
3543     Known.knownNot(~DemandedMask);
3544 
3545     if (Known.KnownFPClasses == fcNone) {
3546       if (isa<PoisonValue>(V))
3547         return false;
3548       replaceUse(U, PoisonValue::get(VTy));
3549       return true;
3550     }
3551 
3552     // Do not try to replace values which are already constants (unless we are
3553     // folding to poison). Doing so could promote poison elements to non-poison
3554     // constants.
3555     if (isa<Constant>(V))
3556       return false;
3557 
3558     Value *FoldedToConst = getFPClassConstant(VTy, Known.KnownFPClasses);
3559     if (!FoldedToConst || FoldedToConst == V)
3560       return false;
3561 
3562     replaceUse(U, FoldedToConst);
3563     return true;
3564   }
3565 
3566   if (const CallBase *CB = dyn_cast<CallBase>(VInst)) {
3567     FPClassTest NoFPClass = CB->getParamNoFPClass(U.getOperandNo());
3568     DemandedMask &= ~NoFPClass;
3569   }
3570 
3571   if (Depth == MaxAnalysisRecursionDepth) {
3572     Known.knownNot(~DemandedMask);
3573     return false;
3574   }
3575 
3576   Value *NewVal;
3577 
3578   if (VInst->hasOneUse()) {
3579     // If the instruction has one use, we can directly simplify it.
3580     NewVal = SimplifyDemandedUseFPClass(VInst, DemandedMask, Known, I, Depth);
3581   } else {
3582     // If there are multiple uses of this instruction, then we can simplify
3583     // VInst to some other value, but not modify the instruction.
3584     NewVal = SimplifyMultipleUseDemandedFPClass(VInst, DemandedMask, Known, I,
3585                                                 Depth);
3586   }
3587 
3588   if (!NewVal)
3589     return false;
3590   if (Instruction *OpInst = dyn_cast<Instruction>(U))
3591     salvageDebugInfo(*OpInst);
3592 
3593   replaceUse(U, NewVal);
3594   return true;
